<template>
    <v-container fluid class="pa-6 pt-4 fill-height cctv-roi-manage">
      <v-row no-gutters class="fill-height">
        <v-sheet width="100%" height="33">
          <h3 class="font-weight-bold">{{ title }}</h3>
        </v-sheet>
        <v-sheet width="100%" height="calc(100% - 32px)" class="pt-2 overflow-hidden cctv-roi-manage-contents">
          <v-row no-gutters class="pa-0 fill-height">
            <v-card width="170" color="login_bg" class="pa-2 fill-height red">
              <v-list nav dense style="max-height: 1116px;
                                      overflow-y: auto;
                                      background: #eef2f5;">
                <v-list-item-group v-model="selected" color="primary" class="login_bg">
                  <template v-for="(item, i) in list">
                    <v-list-item :key="item.cctv_id" :disabled="item.cctv_id == selected" :input-value="item.cctv_id" :value="item.cctv_id" class="login_bg" @click="onCCTV(item)">
                      <v-list-item-content>
                        <v-list-item-title v-text="`${item.camera_nm}(${item.camera_desc})`" class="text-subtitle-2" />
                      </v-list-item-content>
                    </v-list-item>
                  </template>
                </v-list-item-group>
              </v-list>
            </v-card>
            <v-col class="ml-4 fill-height overflow-x-hidden overflow-y-auto">
              <v-card width="100%" height="100%" outlined rounded="md" class="pa-3 px-5">
                <v-sheet height="33">
                  <h3 class="font-weight-bold">{{ `${selectedItem.cctv_id}` }}</h3>
                </v-sheet>
                <v-sheet height="35" class="d-flex align-center">
                  <template v-for="button in controlButtonFirst">
                    <v-btn
                      :key="button.id"
                      height="30"
                      color="btn_bg"
                      class="mr-2 px-0"
                      elevation="0"
                      outlined
                      rounded
                      :disabled="button.isDisable()"
                      small
                      :width="button.text ? 120 : 35"
                      @click="button.onClick"
                    >
                      <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                        <v-icon size="14">{{ button.icon }}</v-icon>
                        <template v-if="button.text">
                          <span class="ml-1">{{ $t(button.text) }}</span>
                        </template>
                      </div>
                    </v-btn>
                  </template>
                </v-sheet>
                <v-sheet height="35" class="d-flex align-center">
                  <template v-for="button in controlButtonSecond">
                    <v-btn
                      :key="button.id"
                      height="30"
                      color="btn_bg"
                      class="mr-2 px-0"
                      elevation="0"
                      outlined
                      rounded
                      :disabled="button.isDisable()"
                      small
                      :width="button.text ? 120 : 35"
                      @click="button.onClick"
                    >
                      <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                        <v-icon size="14">{{ button.icon }}</v-icon>
                        <template v-if="button.text">
                          <span class="ml-1">{{ $t(button.text) }}</span>
                        </template>
                      </div>
                    </v-btn>
                  </template>
                  <v-spacer />
                  <v-tooltip top>
                    <template #activator="{ on, attrs }">
                      <v-btn
                        icon
                        v-bind="attrs"
                        v-on="on"
                      >
                        <svg-icon width="20" height="20" icon-class="help" color="#e6e6e6" />
                      </v-btn>
                    </template>
                    <span>{{ `Ctrl + 휠` }}</span>
                  </v-tooltip>
                  <template v-for="(button, index) in scaleButton">
                    <v-btn
                      :key="`${button.id}_btn`"
                      height="30"
                      color="btn_bg"
                      class="mr-2 px-0"
                      elevation="0"
                      outlined
                      rounded
                      :disabled="button.isDisable()"
                      small
                      :width="button.text ? 84 : 35"
                      @click="button.onClick"
                    >
                      <div class="font-weight-bold" :class="[button.isDisable() ? 'gray--text' : 'content--text']">
                        <v-icon size="14">{{ button.icon }}</v-icon>
                        <template v-if="button.text">
                          <span class="ml-1">{{ $t(button.text) }}</span>
                        </template>
                      </div>
                    </v-btn>
                    <template v-if="index == 0">
                      <v-sheet width="50" class="ml-2 mr-4 text-center" :key="index">
                        <span>{{ `${scaleFactor * 10}%` }}</span>
                      </v-sheet>
                    </template>
                  </template>
                  <v-sheet width="416" />
                </v-sheet>
                <v-sheet width="100%" min-width="700" height="calc(100% - 33px - 70px)" class="pt-1" ref="roiContainer">
                  <template v-if="isLoading">
                    <v-row no-gutters class="align-center justify-center fill-height">
                      <v-progress-circular indeterminate color="secondary" />
                    </v-row>
                  </template>
                  <template v-else>
                    <v-row no-gutters class="fill-height">
                      <v-col
                        class="pa-0 cctv-roi-manage-contents-image"
                        @mouseenter="onMouseEnter"
                        @mouseleave="onMouseLeave"
                        @wheel="onWheel"
                        ref="roiImage"
                      >
                        <v-sheet :width="scaleWidth/(scaleFactor / 0.1)" :height="scaleHeight/(scaleFactor / 0.1)" 
                          :style="`aspect-ratio: ${imageRatio}; transform: scale(${scaleFactor * 0.1}) !important;`">
                          <v-stage
                            :config="configKonva"
                            @click="onHandleClick"
                            @mouseenter="handleMouseEnter"
                            @mouseleave="handleMouseLeave"
                          >
                            <v-layer ref="layer">
                              <v-image
                                :config="{
                                  image: cctvImg,
                                  width: scaleWidth,
                                  height: scaleHeight,
                                  x: 0,
                                  y: 0,
                                }"
                                :style="`aspect-ratio: ${imageRatio};`"
                              />
                            </v-layer>
                          </v-stage>
                        </v-sheet>
                      </v-col>
                      <v-divider vertical class="mx-2" />
                      <v-sheet width="300" class="d-flex flex-column">
                        <v-col class="text-center overflow-hidden py-1" style="min-height: 190px;">
                          <h4 class="font-weight-bold secondary--text">{{ $t('standardGridCoord') }}</h4>
                          <v-card width="100%" outlined height="calc(100% - 100px)" class="mt-1 pa-2 overflow-y-auto text-left">
                            <v-radio-group 
                              v-model="selectedItem.sortDirection"
                              :disabled="this.selectedItem.initial_coordinates.length > 1"
                              @change="handleStandardGrid"
                              mandatory>
                              <template v-for="(button, index) in sortDirectionButton">
                                <v-radio
                                  :key="`${button.id}_btn`"
                                  :label="$t(button.text)"
                                  :value="button.id"
                                  >
                                </v-radio>
                              </template>
                            </v-radio-group>
                          </v-card>
                        </v-col>
                        <v-col class="text-center overflow-hidden py-1">
                          <h4 class="font-weight-bold secondary--text">{{ $t('gridUnitSetting') }}</h4>
                          <v-card width="100%" outlined height="calc(100% - 160px)" class="mt-1 pa-2 overflow-y-auto text-left">
                            <v-radio-group 
                              v-model="selectedItem.gridUnit"
                              @change="handleGridUnit"
                              mandatory>
                              <v-radio
                                v-for="(button, index) in gridUnitButton"
                                :key="`${button.id}_btn`"
                                :label="$t(button.text)"
                                :value="button.id"
                                >
                              </v-radio>
                            </v-radio-group>
                          </v-card>
                        </v-col>
                        <v-col class="text-center py-1">
                          <h4 class="font-weight-bold secondary--text">모델 선택</h4>
                          <v-sheet width="100%" height="calc(100% - 27px - 8px)" class="mt-2 d-flex flex-row flex-wrap align-content-space-between">
                            <v-card width="100%" outlined class="pa-3">
                              <template v-for="(model, model_index) in modelList">
                                <v-checkbox
                                  :key="model_index"
                                  v-model="modelSelectedItem[model.key]"
                                  :label="model.text"
                                  class="font-weight-medium"
                                  :class="[{ 'mt-3' : model_index !== 0 }]"
                                />
                              </template>
                            </v-card>
                          </v-sheet>
                        </v-col>
                        <v-col class="text-center py-1">
                          <h4 class="font-weight-bold secondary--text">{{ $t('refGridDetectonSetting') }}</h4>
                          <v-sheet width="100%" height="calc(100% - 27px - 8px)" class="mt-1 d-flex flex-row flex-wrap align-content-space-between">
                            <v-card width="100%"  outlined height="calc(100% - 120px)" class="pa-2">
                              <v-radio-group 
                                v-model="selectedItem.detectionMode"
                                :disabled="this.selectedItem.initial_coordinates.length > 1"
                                @change="handleDetectionMode"
                                mandatory>
                                <v-radio
                                  v-for="(button, index) in GridDetectonButton"
                                  :key="`${button.id}_btn`"
                                  :label="$t(button.text)"
                                  :value="button.id"
                                  >
                                  <template v-if="button.id==='click'" v-slot:label>
                                    <span>{{ $t(button.text) }}</span>
                                    <v-btn
                                      v-if="clickArea.x != null && clickArea.y != null"
                                      height="20"
                                      class="ml-2 px-0"
                                      elevation="0"
                                      outlined
                                      rounded
                                      small
                                      :width="button.text ? 60 : 35"
                                      @click="resetClickArea()"
                                    >
                                      <span>재설정</span>
                                    </v-btn>
                                  </template>
                                </v-radio>
                              </v-radio-group>
                              <!-- <v-col v-if="selectedItem.detectionMode == 'click'" class="d-flex align-content-center">
                                <span style="flex-wrap: wrap;" class="d-flex align-content-center">범위</span>
                                <v-sheet width="100">
                                  <v-text-field
                                  v-model="search_radius"
                                  type="number"
                                  outlined>
                                </v-text-field>
                                </v-sheet>
                                <span style="flex-wrap: wrap;" class="d-flex align-content-center">px</span>
                              </v-col> -->
                            </v-card>
                            <v-btn
                              height="36"
                              color="btn_bg"
                              class="mt-auto px-0"
                              elevation="0"
                              outlined
                              rounded
                              small
                              width="100%"
                              @click="saveGrid"
                            >
                              <div class="font-weight-bold content--text">
                                {{ `${$t('setupComplete')}` }}
                              </div>
                            </v-btn>
                          </v-sheet>
                        </v-col>
                      </v-sheet>

                      
                    <DxFileUploader
                      :ref="dxImageFileloaderRef"
                      :multiple="false"
                      upload-mode="useButton"
                      :visible="false"
                      @value-changed="onFileValueChanged"
                      :accept="accept"
                    />
                    </v-row>
                  </template>
                </v-sheet>
              </v-card>
            </v-col>
          </v-row>
          <span class="cctv-roi-manage-contents-mobile">해당 화면은 모바일 환경에서 지원되지 않습니다.</span>
        </v-sheet>
      </v-row>
    </v-container>
  </template>
  
  <script>
  
  import { getUserCd } from '@/utils/token'
  import { getRoiList, getImage } from '@/api/realTimeVideoSafetyManagement/safetyMonitoringZoneManage.js'
  import { getExtension } from '@/utils/common.js'
  import { gridDetectionAll, adjustGridSize, saveGrid, loadGrid, getRawImg, getInitialImage, updateSortDirection } from '@/api/realTimeVideoSafetyManagement/InventoryCheckGridManage.js'
  import { DxFileUploader } from 'devextreme-vue/file-uploader'
  import notify from 'devextreme/ui/notify'

  import baseview from '@/views/base/baseview.vue'
  export default {
    mixins: [baseview],
    name: 'SafetyMonitoringZoneManage',
    components: {
      DxFileUploader
    },
    data() {
      return {
        title: this.$t('inventoryCheckGridManage'),
        selected: null,
        selectedItem: {},
        limitLength: 3,
        list: [],
        legacyList: [],
        controlButtonFirst: [
          { id: 'gridDetection', text: 'refGridDetection', icon: 'mdi-magnify', isDisable: () => this.selectedItem.initial_coordinates.length > 1, onClick: () => this.standardGridDetection() },
          { id: 'upExtend', text: 'extendUp', icon: 'mdi-arrow-up-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('up_extend') },
          { id: 'downExtend', text: 'extendDown', icon: 'mdi-arrow-down-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('down_extend') },
          { id: 'leftExtend', text: 'extendLeft', icon: 'mdi-arrow-left-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('left_extend') },
          { id: 'rightExtend', text: 'extendRight', icon: 'mdi-arrow-right-bold', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('right_extend') },
          { id: 'image', text: '테스트 이미지 로드', icon: 'mdi-circle', isDisable: () => false, onClick: () => this.testImage(true) },
          { id: 'takeImage', text: '이미지 가져오기', icon: 'mdi-upload', isDisable: () => false, onClick: () => this.uploadImage(true) },
        ],
        controlButtonSecond: [
          { id: 'reset', text: 'reset', icon: 'mdi-refresh', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.loadRawImage() },
          { id: 'downShrink', text: '위로 축소', icon: 'mdi-arrow-down-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('up_shrink') },
          { id: 'upShrink', text: '아래로 축소', icon: 'mdi-arrow-up-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('down_shrink') },
          { id: 'rightShrink', text: '왼쪽으로 축소', icon: 'mdi-arrow-right-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('left_shrink') },
          { id: 'leftShrink', text: '오른쪽으로 축소', icon: 'mdi-arrow-left-bold-outline', isDisable: () => this.selectedItem.initial_coordinates.length == 0, onClick: () => this.adjustSize('right_shrink') },
        ],
        scaleButton: [
          { id: 'scaleMinus', text: '', icon: 'mdi-minus', isDisable: () => this.scaleFactor == this.scaleMin, onClick: () => this.scaleFactor -= 1 },
          { id: 'scalePlus', text: '', icon: 'mdi-plus', isDisable: () => this.scaleFactor >= this.scaleMax, onClick: () => this.scaleFactor += 1 },
        ],
        sortDirectionButton: [
          { id: 'up', text: 'stadardUp' },
          { id: 'down', text: 'standardDown' },
          { id: 'left', text: 'stadardLeft' },
          { id: 'right', text: 'stadardRight' },
        ],
        gridUnitButton: [
          { id: '1', text: '1x1m'},
          { id: '0.5', text: '0.5x0.5m'},
        ],
        GridDetectonButton: [
          { id: 'all', text: 'entireArea'},
          { id: 'click', text: 'mouseClickArea'},
        ],
        isHovering: false,
        isLoading: true,
        configKonva: {
          width: 0,
          height: 0,
        },

        inputMin: 100,
        inputWidthMax: 1000,
        inputHeightMax: 800,
        scaleWidth: 0,
        scaleHeight: 0,
        imageRatio: 16/9,
        isScaleFactor: false,
        //scaleFactor default =  10
        scaleFactor: 3,
        scaleMax: 20,
        scaleMin: 1,
        closeThreshold: 10,
        cctvImg: null,
        selectModel: "Detection",
        inputWidth: 900,
        inputHeight: 600,
        originalWidth: 0, // 이미지 원본 너비
        originalHeight: 0, // 이미지 원본 높이
        search_radius: 1500, 
        use_click: false,
        clickArea: {x: null ,y: null},
        image_base64: null,

        dxImageFileloaderRef: 'dxImageFileloaderRef',
        accept: 'image/*',
        allowedFileExtensions: ['jpg', 'jpeg', 'gif', 'png'],
        modelSelectedItem: {},
        modelList: [
          { text: 'BWTS 공정진행율', model_nm: 'BWTS_PROCESS', key: 'bwts_process' },
          { text: 'SCRUBBER 공정진행율', model_nm: 'SCRUBBER_RPOCESS', key: 'scrubber_process' },
          { text: 'BWTS 원소재', model_nm: 'BWTS_MATERIALS', key: 'bwts_materials' },
          { text: 'SCRUBBER 원소재', model_nm: 'SCRUBBER_MATERIALS', key: 'scrubber_materials' },
          { text: 'NOX', model_nm: 'NOX', key: 'nox' },
          { text: 'PRE ABSORBER ', model_nm: 'PRE_ABSORBER', key: 'pre_absorber' }
        ]
      }
    },
    computed: {
    },
    async mounted() {
      await this.onMounted()
    },
    watch: {
    },
    methods: {
      onMounted() {
        getRoiList()
          .then(res => {
            this.list = res.list.map(el => {
              const { model_list, ...rest } = el
              return {
                ...rest,
              }
            })
            this.legacyList = JSON.parse(JSON.stringify(this.list))
            if(this.list.length !== 0) {
              //Load API있을경우 수정 필요
              this.selected = this.list[0].cctv_id
              this.selectedItem = this.list[0]
              this.selectedItem.initial_coordinates = []
              if(this.selected == null) {
                this.selected = this.list[0].cctv_id
                this.selectedItem = this.list[0]
                this.selectedItem.initial_coordinates = []
              } else {
                this.selectedItem = this.list.find(el => el.cctv_id == this.selected)
              }
              //이미지 로드
              this.loadImage()
            }
          })
      },
      
      onCCTV(param) {
        this.selected = param.cctv_id
        this.selectedItem = param
        this.loadImage(this.selected)
      },
      onMouseEnter() {
        this.isHovering = true
      },
      onMouseLeave() {
        this.isHovering = false
      },
      onWheel(event) {
        if (event.ctrlKey) {
          event.preventDefault()
          if (event.deltaY < 0 && this.scaleFactor < this.scaleMax) {
            this.scaleFactor++
          } else if (event.deltaY > 0 && this.scaleFactor > this.scaleMin) {
            this.scaleFactor--
          }
        }
      },
      createImg(imgParam) {
        const img = new Image()
        img.src = imgParam
        img.onload = () => {
          this.cctvImg = img
          this.originalWidth = img.width
          this.originalHeight = img.height
          if (this.isScaleFactor) {
            this.scaleWidth = img.width * this.scaleFactor
            this.scaleHeight = img.height * this.scaleFactor
          } else {
            this.scaleWidth = this.inputWidth
            this.scaleHeight = this.inputHeight
          }
          this.configKonva.width = this.scaleWidth
          this.configKonva.height = this.scaleHeight
        }
      },


      drawImage(image) {
        if(image) {
          const byteCharacters = atob(image)
          const byteNumbers = new Array(byteCharacters.length).fill().map((_, i) => byteCharacters.charCodeAt(i))
          const byteArray = new Uint8Array(byteNumbers)
          const blob =  new Blob([byteArray], { type: 'image/jpeg' }) // Blob 생성
          this.createImg(URL.createObjectURL(blob)) // 이미지 표시 함수 호출
        }
      },
      clearImg() {
      // 이미지 초기화
        this.cctvImg = null;
        this.originalWidth = 0
        this.originalHeight = 0
        this.scaleWidth = 0
        this.scaleHeight = 0
        this.configKonva = {
          width: 0,
          height: 0,
        }
      },
      //격자 검출 : 전체영역(자동)
      standardGridDetection() {
        this.use_click = false
        this.selectedItem.detectionMode = 'all'
        this.clickArea.x = null 
        this.clickArea.y = null
        const param = {
          image_base64: this.image_base64,
          click_coordinates: [this.clickArea.x, this.clickArea.y],
          use_click: this.use_click
        }
        gridDetectionAll(param).then(res => {
          this.selectedItem.initial_coordinates = res.initial_coordinates
          this.selectedItem.unique_id = res.unique_id
          this.drawImage(res.image_base64)
        })
        .finally(() => {
          this.handleStandardGrid()
        })
      },
      //기준격자검출 : 격자 조정(확장 및 축소)
      async adjustSize(size) {
        const param = {
          initial_coordinates: this.selectedItem.initial_coordinates,
          sort_direction: this.selectedItem.sortDirection,
          unique_id: this.selectedItem.unique_id,
          operations: [[size, 1]]
        }
        await adjustGridSize(param).then(async res => {
          this.selectedItem.initial_coordinates = res.updated_coordinates
          this.drawImage(res.image_base64)
        })
        .catch(el => {
          if(el.response.data.message == "Cannot shrink below one row." || el.response.data.message == "Cannot shrink below one column." ) {
            this.$vToastify.error({ body: this.$t('errorToastMsg') + ': ' + this.$t('기준 격자를 지울 수  없습니다') })
          }
        })
      },
      //격자좌표기준 설정
      handleStandardGrid() {
        if(this.selectedItem.initial_coordinates.length != 0) {
          const param = {
            sort_direction: this.selectedItem.sortDirection,
            unique_id: this.selectedItem.unique_id,
          }
          updateSortDirection(param).then(async res => {
            console.log(res)
          })
        }
      },
      //격자단위설정
      handleGridUnit() {
      },
      //기준격자검출설정
      handleDetectionMode() {
        if(this.selectedItem.detectionMode == 'click') {
          this.use_click = true
          this.search_radius = 1500
        }
        else {
          this.use_click = false
          if( this.selectedItem.initial_coordinates.length != 0) {
            this.standardGridDetection()
          }
        }
      },
      // 마우스 클릭
      onHandleClick(e) {
        if (!this.use_click) return
        const pos = e.target.getStage().getPointerPosition()
        this.clickArea.x = Math.round(pos.x)
        this.clickArea.y = Math.round(pos.y)
        const param = {
          image_base64: this.image_base64,
          click_coordinates: [this.clickArea.x, this.clickArea.y],
          search_radius: parseInt(this.search_radius),
          use_click: this.use_click,
        }
        gridDetectionAll(param).then(res => {
          this.selectedItem.initial_coordinates = res.initial_coordinates
          this.selectedItem.unique_id = res.unique_id
          this.drawImage(res.image_base64)
        })
        .catch((el) => {
          if(el.response.data.message == "No red squares detected in the image." ) {
            this.$vToastify.error({ body: this.$t('errorToastMsg') + ': ' + this.$t('지정된 지점 근처에서 빨간색 사각형이 감지되지 않았습니다.') })
          }
        })
        .finally(() => {
          this.use_click = false
        })
        e.target.getStage().container().style.cursor = 'default'
      },
      //마우스 커서 변경
      handleMouseEnter(e) {
        const stage = e.target.getStage()                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        stage.container().style.cursor = this.use_click ? 'pointer' : 'default'
      },
      handleMouseLeave(e) {                                                                    
        const stage = e.tarsssssget.getStage()
        stage.container().style.cursor = this.use_click ? 'pointer' : 'default'
      },
      //재설정 버튼
      resetClickArea() {
        this.use_click = true
        this.clickArea.x = null 
        this.clickArea.y = null
      },

      saveGrid() {
        if(this.selectedItem.cctv_id) {
          const handleSave = () => {
            this.openLoading('saving')
            const param = {
              unique_id: this.selectedItem.unique_id,
              sort_direction: this.selectedItem.sortDirection,
              initial_coordinates: this.selectedItem.initial_coordinates,
              grid_unit: this.selectedItem.gridUnit,
              camera_id: this.selectedItem.cctv_id,
              bwts_pro_run: this.modelSelectedItem['bwts_process'],
              scr_pro_run: this.modelSelectedItem['scrubber_process'],
              bwts_mat_run: this.modelSelectedItem['bwts_materials'],
              scr_mat_run: this.modelSelectedItem['scrubber_materials'],
              nox_run: this.modelSelectedItem['nox'],
              pre_absorber_run: this.modelSelectedItem['pre_absorber'],
              created_by: getUserCd(),
              updated_by: getUserCd(),
              image_base64: this.image_base64
            }
            saveGrid(param).then(res => {
              console.log(res)
              // this.onMounted()
            })
            .finally(() => {
              this.endLoading()
            })

          }
          if(!this.selectedItem.unique_id) {
            this.vToastify(
            this.$t('기준격자를 먼저 검출해 주세요'),
            'warn',
            current => {
              this.endLoading()
            }, null, true)
          }
          else {
            this.vToastifyPrompt(
            this.$t('저장하시겠습니까?'),
              'info',
            current => {
              handleSave()
            }, null, true)
          }
        }
      },

      //초기 이미지 로드
      async loadRawImage() {
        this.isLoading = true
        let responseTimeout; // 응답 대기 타이머 변수
        // 딜레이 처리 타이머 (예: 5초 후 응답 없을 시 처리)
        responseTimeout = setTimeout(() => {
          this.clearImg();
          this.isLoading = false;
          console.warn('응답 지연으로 인해 처리가 중단되었습니다.');
        }, 5000); // 5초 딜레이
        // console.log('test')
        let param = {
          'unique_id':this.selectedItem.unique_id
        }
        await getRawImg(param).then(async res => {
          // console.log(res)
          clearTimeout(responseTimeout); // 정상 응답 시 타이머 해제
          this.image_base64 = res.origin_image_base64
          this.selectedItem.initial_coordinates = []
          this.selectedItem.detectionMode = 'all'
          this.clickArea.x = null 
          this.clickArea.y = null
          this.originalWidth = res.img_size.width
          this.originalHeight = res.img_size.height
          this.inputWidth = res.img_size.width
          this.inputHeight = res.img_size.height
          let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
          this.imageRatio = x/y
          this.drawImage(this.image_base64)
          this.isLoading = false;
        })
      },

      async loadImage() {
        this.isLoading = true
        let responseTimeout; // 응답 대기 타이머 변수
        // 딜레이 처리 타이머 (예: 5초 후 응답 없을 시 처리)
        responseTimeout = setTimeout(() => {
          this.clearImg();
          this.isLoading = false;
          console.warn('응답 지연으로 인해 처리가 중단되었습니다.');
        }, 5000); // 5초 딜레이
        
        this.selectedItem.initial_coordinates = []
        this.selectedItem.detectionMode = 'all'
        this.clickArea.x = null 
        this.clickArea.y = null
        
        // 저장된 그리드 데이터가 있는지 확인 하는 코드
        let param = {
          'camera_id': this.selected
        }
        await loadGrid(param).then(async res => {   
          console.log(res)
          this.isLoading = false
          //로드내용 처리
          clearTimeout(responseTimeout); // 정상 응답 시 타이머 해제
          this.image_base64 = res.image_base64
          //모델 선택 내용
          this.modelSelectedItem['bwts_process'] = res.bwts_pro_run
          this.modelSelectedItem['scrubber_process'] = res.scr_pro_run
          this.modelSelectedItem['bwts_materials'] = res.bwts_mat_run
          this.modelSelectedItem['scrubber_materials'] = res.scr_mat_run
          this.modelSelectedItem['nox'] = res.nox_run
          this.modelSelectedItem['pre_absorber'] = res.pre_absorber_run
          if(this.image_base64) {
              this.originalWidth = res.img_size.width
              this.originalHeight = res.img_size.height
              this.inputWidth = res.img_size.width
              this.inputHeight = res.img_size.height
              let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
              this.imageRatio = x/y
              //상태값
              this.selectedItem.unique_id = res.unique_id
              this.selectedItem.sortDirection = res.sort_direction
              this.selectedItem.gridUnit = res.grid_unit.toString()
              this.selectedItem.initial_coordinates = [0,1,2]
              this.drawImage(this.image_base64)
            } else {
              this.clearImg()
            }
        }).catch(res=>{
          getImage(this.selected)
          .then(async res => {
            clearTimeout(responseTimeout); // 정상 응답 시 타이머 해제
            this.image_base64 = res.img_decode_data
            if(this.image_base64) {
              this.originalWidth = res.img_size.width
              this.originalHeight = res.img_size.height
              this.inputWidth = res.img_size.width
              this.inputHeight = res.img_size.height
              let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
              this.imageRatio = x/y
              this.drawImage(this.image_base64)
            } else {
              this.clearImg()
            }
          })
          .finally(() => {
            setTimeout(() => {
              this.isLoading = false
            }, 500)
          })
        })
      },

      async testImage(loading) {
        this.isLoading = true
        let responseTimeout; // 응답 대기 타이머 변수
        // 딜레이 처리 타이머 (예: 5초 후 응답 없을 시 처리)
        responseTimeout = setTimeout(() => {
          this.clearImg();
          this.isLoading = false;
          console.warn('응답 지연으로 인해 처리가 중단되었습니다.');
        }, 5000); // 5초 딜레이

        this.selectedItem.initial_coordinates = []
        this.selectedItem.detectionMode = 'all'
        this.clickArea.x = null 
        this.clickArea.y = null
        await getInitialImage(this.selected)
          .then(async res => {
            clearTimeout(responseTimeout); // 정상 응답 시 타이머 해제
            this.image_base64 = res.image_base64
            if(this.image_base64) {
              this.originalWidth = res.img_size.width
              this.originalHeight = res.img_size.height
              this.inputWidth = res.img_size.width
              this.inputHeight = res.img_size.height
              let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
              this.imageRatio = x/y
              this.drawImage(this.image_base64)
            } else {
              this.clearImg()
            }
          })
          .finally(() => {
            setTimeout(() => {
              this.isLoading = false
            }, 500)
          })
      },

      async uploadImage(e) {
        //현재 cctv 이미지 로드
        this.isLoading = true
        let responseTimeout; // 응답 대기 타이머 변수
        // 딜레이 처리 타이머 (예: 5초 후 응답 없을 시 처리)
        responseTimeout = setTimeout(() => {
          this.clearImg();
          this.isLoading = false;
          console.warn('응답 지연으로 인해 처리가 중단되었습니다.');
        }, 5000); // 5초 딜레이
        
        this.selectedItem.initial_coordinates = []
        this.selectedItem.detectionMode = 'all'
        this.clickArea.x = null 
        this.clickArea.y = null
        
        // 저장된 그리드 데이터가 있는지 확인 하는 코드
        let param = {
          'camera_id': this.selected
        }
        await getImage(this.selected)
        .then(async res => {
          clearTimeout(responseTimeout); // 정상 응답 시 타이머 해제
          this.image_base64 = res.img_decode_data
          if(this.image_base64) {
            this.originalWidth = res.img_size.width
            this.originalHeight = res.img_size.height
            this.inputWidth = res.img_size.width
            this.inputHeight = res.img_size.height
            let [x, y] = res.ratio ? res.ratio.split(':').map(Number) : [4, 3]
            this.imageRatio = x/y
            this.drawImage(this.image_base64)
          } else {
            this.clearImg()
          }
        })
        .finally(() => {
          setTimeout(() => {
            this.isLoading = false
          }, 500)
        })
      },
      onFileValueChanged(e) {
        console.log('fileUpoload', e)
        let file = e.value[0]
        
        var reader = new FileReader()
        reader.readAsDataURL(file)
        reader.onload = () => {
          // 확장자랑 파일명 가져오기
          let subFileName = getExtension(file.name)

          let index = this.allowedFileExtensions.findIndex(element => element == subFileName[1])

          if (index < 0) {
            notify(this.$t('업로드할 수 없는 확장자입니다.'), 'error', 300)
            return
          }
          this.selectedItem.initial_coordinates = []
          this.image_base64 = reader.result.split(',')[1]
          this.drawImage(this.image_base64)
        }
        reader.onerror = error => {
          console.error('error', error)
          // this.$vToastify.error({ body: '파일업로드에 실패하였습니다. 다시 시도해주시기 바랍니다.' })
          this.vToastify(this.$t('파일업로드에 실패하였습니다. 다시 시도해주시기 바랍니다.'), 'error')
        }
      }
    },
  }
  </script>
  
