import dayjs from 'dayjs'

export function getForamtDate(date) {
  var year = date.getFullYear()
  var month = 1 + date.getMonth()
  month = month >= 10 ? month : '0' + month
  var day = date.getDate()
  day = day >= 10 ? day : '0' + day
  return new Date(Number(year), Number(year), Number(day))
}

export function getDateToStringMonth(date) {
  var year = date.getFullYear()
  var month = 1 + date.getMonth()
  month = month >= 10 ? month : '0' + month
  return year.toString() + month.toString()
}

export function getDateToStringDte(date) {
  var year = date.getFullYear()
  var month = 1 + date.getMonth()
  month = month >= 10 ? month : '0' + month
  var day = date.getDate()
  day = day >= 10 ? day : '0' + day
  return year.toString() + month.toString() + day.toString()
}

export function getStringToDate(str) {
  var y = str.substr(0, 4)
  var m = str.substr(4, 2)
  var d = str.substr(6, 2)
  return new Date(y, m - 1, d)
}

// 파일명, 확장자 내보내기
export function getExtension(fileName) {
  let fileLen = fileName.length

  let lastDot = fileName.lastIndexOf('.')
  let extension = fileName.substring(lastDot + 1, fileLen)
  let baseName = fileName.substring(0, lastDot)
  return [baseName, extension]
}

//현재일자를 'format에 맞게 변형 YYYY-MM-DD'
export function getCurrentDate() {
  return dayjs(new Date()).format('YYYY-MM-DD')
}

//현재일자를 'format에 맞게 변형 YYYY'
export function getCurrentYear() {
  return dayjs(new Date()).format('YYYY')
}

// 올해의 1월 1일 'format에 맞게 변형 YYYY-MM-DD' ex) 
export function getNewYear() {
  return dayjs(new Date())
    .set("month", 0)
    .set("date", 1)
    .format('YYYY-MM-DD')
}

//현재일자에서 이전달을 'format에 맞게 변형 YYYY-MM-DD' ex) a=1 한달전
export function getPreMonth(month) {
  return dayjs(new Date())
    .subtract(month, 'month')
    .format('YYYY-MM-DD')
}

//현재일자에서 이전일을 'format에 맞게 변형 YYYY-MM-DD' ex) a=1 1일전
export function getPreDay(day) {
  return dayjs(new Date())
    .subtract(day, 'day')
    .format('YYYY-MM-DD')
}
//현재일자에서 이전일을 'format에 맞게 변형 YYYY.MM.DD' ex) a=1 1일전
export function getPreDayYyyymmdd(day) {
  return dayjs(new Date())
    .subtract(day, 'day')
    .format('YYYYMMDD')
}

//특정일자를 'format에 맞게 변형 YYYY-MM-DD'
