// time : 4자리 숫자 or HH:mm
//특정 시간을 'format에 맞게 변형 YYYY-MM-DD HH:mm'
export function getDateToTime(time) {
  if (time) {
    let date = new Date()
    // 숫자만 남기기
    let onlyNumber = time.replace(/[^0-9]/g, '')
    let hour = onlyNumber.substring(0, 2)
    let minute = onlyNumber.substring(2, 4)
    date.setHours(hour)
    date.setMinutes(minute)
    return dayjs(date).format('YYYY-MM-DD HH:mm')
  } else {
    return null
  }
}

