// 4자리 입력 숫자 시간 유효성 검사     맞으면 true 틀리면 false
export function timeCheck(inputTime) {
  let pattern = /^([1-9]|[01][0-9]|2[0-3])([0-5][0-9])$/
  let time = inputTime.replace(/[^0-9]/g, '')
  if (!pattern.test(time) || time.length !== 4) {
    return false
  } else {
    return true
  }
}

/**
 * 좌, 우측문자열채우기
 *  - str : 원 문자열
 *  - padLen : 최대 채우고자 하는 길이
 *  - padStr : 채우고자하는 문자(char)
 */
export function lpad(str, padLen, padStr) {
  if (padStr.length > padLen) {
    //채우고자 하는 문자열이 요청 길이보다 클때
    return str + ''
  }
  str += '' // 문자로
  padStr += '' // 문자로
  while (str.length < padLen) str = padStr + str
  str = str.length >= padLen ? str.substring(0, padLen) : str
  return str
}

export function rpad(str, padLen, padStr) {
  if (padStr.length > padLen) {
    //채우고자 하는 문자열이 요청 길이보다 클때
    return str + ''
  }
  str += '' // 문자로
  padStr += '' // 문자로
  while (str.length < padLen) str += padStr
  str = str.length >= padLen ? str.substring(0, padLen) : str
  return str
}

//현재일자에서 이전일을 'format에 맞게 변형 YYYY-MM-DD' 
export function getPreDate(date) {
  return dayjs(new Date(date))
    .subtract(1, 'day')
    .format('YYYY-MM-DD')
}
//현재일자에서 이후일을 'format에 맞게 변형 YYYY-MM-DD' 
export function getProDate(date) {
  return dayjs(new Date(date))
    .add(1, 'day')
    .format('YYYY-MM-DD')
}

//date 선택된 날짜를 'format에 맞게 변형 YYYY.MM.DD' 
export function getDateEditorValue(eventValue) {
      if (eventValue) {
        const date = new Date(eventValue)
        const year = date.getFullYear()
        const month = String(date.getMonth() + 1).padStart(2, '0')
        const day = String(date.getDate()).padStart(2, '0')
        return `${year}.${month}.${day}`
      } else {
        return null
      }
}

//그룹 데이터 필터 공통
export function getFilterGroupAuthList(data,compId) {
    let filterGroupAuthData = data.list.slice().filter(element => element.grpAuthCd != 'super') // super 제외
     
    if (compId !== 'IGNS') { // IGNS가 아닌 경우 manager, normal 만 반환
        filterGroupAuthData = filterGroupAuthData.filter(element => element.grpAuthCd != 'master' ) // master 제외
        return filterGroupAuthData;
    }
    else {
      return filterGroupAuthData;  
    }
}

//만 나이 계산
//birthDateStr 'yyyyMMdd' ex) '19940311'
export function calculateAge(birthDateStr) {
  if (birthDateStr) {
    const today = new Date();
    const year = parseInt(birthDateStr.substring(0, 4));
    const month = parseInt(birthDateStr.substring(4, 6)) - 1; // 월은 0부터 시작
    const day = parseInt(birthDateStr.substring(6, 8));
    const birthDate = new Date(year, month, day);

    let age = today.getFullYear() - birthDate.getFullYear();
    const monthDifference = today.getMonth() - birthDate.getMonth();
    const dayDifference = today.getDate() - birthDate.getDate();

    // 생일이 지났는지 여부 확인
    if (monthDifference < 0 || (monthDifference === 0 && dayDifference < 0)) {
      age--;
    }

    return age;
  }
  else {
    return 0;
  }
}